import 'package:flutter/material.dart'; import '../../core/database/database_helper.dart'; class InventoryScreen extends StatefulWidget{const InventoryScreen({super.key});@override State<InventoryScreen> createState()=>_I();} class _I extends State<InventoryScreen>{List<Map<String,dynamic>> p=[];void initState(){super.initState();ld();}Future<void>ld()async{final db=await DatabaseHelper.instance.database;final r=await db.query('products');setState(()=>p=r);}Widget build(BuildContext c){return Scaffold(appBar:AppBar(title:const Text('Inventory Pro'),backgroundColor:Colors.white),body:ListView.builder(itemCount:p.length,itemBuilder:(_,i){final it=p[i];final low=it['stockQuantity']<10;return Card(margin:const EdgeInsets.symmetric(horizontal:12,vertical:6),child:ListTile(leading:CircleAvatar(backgroundColor:low?Colors.red.shade100:Colors.green.shade100,child:Icon(Icons.inventory,color:low?Colors.red:Colors.green)),title:Text(it['name'],style:const TextStyle(fontWeight:FontWeight.bold)),subtitle:Text('Price:  YER'),trailing:Container(padding:const EdgeInsets.symmetric(horizontal:12,vertical:6),decoration:BoxDecoration(color:low?Colors.red:Colors.green,borderRadius:BorderRadius.circular(20)),child:Text(' left',style:const TextStyle(color:Colors.white)))));}));}}
